export const norm_y_mean = 0.3962661326;
export const norm_y_std = 0.0705244865;

// ─── MLP Forward Pass ───────────────────────────────────────────────────────

function relu(x: number): number {
  return x > 0 ? x : 0;
}

function sigmoid(x: number): number {
  return x >= 0 ? 1 / (1 + Math.exp(-x)) : Math.exp(x) / (1 + Math.exp(x));
}

function dense(input: number[], weights: number[][], biases: number[], activation: 'relu' | 'sigmoid' | 'none'): number[] {
  const output: number[] = [];
  for (let j = 0; j < biases.length; j++) {
    let sum = biases[j];
    for (let i = 0; i < input.length; i++) {
      sum += input[i] * weights[i][j];
    }
    output.push(activation === 'relu' ? relu(sum) : activation === 'sigmoid' ? sigmoid(sum) : sum);
  }
  return output;
}

export function predict(x: number[]): number {
  // x: 5 reward features + 23 context = 28 dim
  const xNorm: number[] = [];
  for (let i = 0; i < 28; i++) {
    xNorm.push((x[i] - norm_X_mean[i]) / (norm_X_std[i] + 1e-8));
  }

  const h1 = dense(xNorm, w0, b0, 'relu');
  const h2 = dense(h1, w1, b1, 'relu');
  const out = dense(h2, w2, b2, 'none')[0];

  // De-normalize: output is in standardized space, convert back to original reward range
  return out * norm_y_std + norm_y_mean;
}

// ─── Feature extraction from a plan ─────────────────────────────────────────

export interface RewardFeatures {
  energy_alignment: number;
  entropy: number;
  pacing_smoothness: number;
  micro_cut_semantic: number;
  energy_transition_alignment: number;
}

export interface PlanContext {
  shot_count: number;
  fps: number;
  duration_frames: number;
  emotion_histogram: number[];
  energy_histogram: number[];
}

/**
 * Build the 28-dim feature vector for a plan, matching dataset_loader._build_features.
 * 5 reward features + 23 context (same as Python training).
 */
export function buildFeatureVector(features: RewardFeatures, context: PlanContext): number[] {
  const feat = [
    features.energy_alignment,
    features.entropy,
    features.pacing_smoothness,
    features.micro_cut_semantic,
    features.energy_transition_alignment,
  ];

  const ctx: number[] = [
    context.shot_count / 20.0,
    context.fps / 30.0,
    context.duration_frames / 3000.0,
    ...(context.emotion_histogram.length >= 10 ? context.emotion_histogram.slice(0, 10) : [...context.emotion_histogram, ...new Array(10 - context.emotion_histogram.length).fill(0)]),
    ...(context.energy_histogram.length >= 10 ? context.energy_histogram.slice(0, 10) : [...context.energy_histogram, ...new Array(10 - context.energy_histogram.length).fill(0)]),
  ];

  return [...feat, ...ctx];
}

/**
 * Dual-track evaluation: R_total = alpha * R_rule + (1-alpha) * R_model
 * - alpha=1.0: pure rule (v20)
 * - alpha=0.0: pure model
 * - alpha=0.7: recommended starting point (favor rule with model enrichment)
 */
export function evaluateWithModel(
  features: RewardFeatures,
  context: PlanContext,
  evaluateFullSequence: (features: RewardFeatures) => number,
  alpha: number = 0.7
): number {
  const x = buildFeatureVector(features, context);
  const rModel = predict(x);
  const rRule = evaluateFullSequence(features);
  return alpha * rRule + (1 - alpha) * rModel;
}